import { useState, useEffect } from 'react';
import axios from 'axios';
import {
    LineChart,
    Line,
    BarChart,
    Bar,
    PieChart,
    Pie,
    Cell,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    ResponsiveContainer,
    Area,
    AreaChart
} from 'recharts';
import { 
    CurrencyDollar, 
    ShoppingCart, 
    Users, 
    Receipt,
    TrendUp,
    TrendDown,
    Funnel
} from '@phosphor-icons/react';
import { 
    Select, 
    SelectContent, 
    SelectItem, 
    SelectTrigger, 
    SelectValue 
} from '../components/ui/select';
import { Skeleton } from '../components/ui/skeleton';
import { useTheme } from '../context/ThemeContext';

const API = `${process.env.REACT_APP_BACKEND_URL}/api`;

const CHART_COLORS = {
    light: {
        primary: '#002FA7',
        secondary: '#10B981',
        tertiary: '#F59E0B',
        quaternary: '#8B5CF6',
        grid: '#E4E4E7',
        text: '#52525B'
    },
    dark: {
        primary: '#3B82F6',
        secondary: '#34D399',
        tertiary: '#FBBF24',
        quaternary: '#A78BFA',
        grid: '#27272A',
        text: '#A1A1AA'
    }
};

const PIE_COLORS = ['#3B82F6', '#10B981', '#F59E0B', '#8B5CF6'];

const KPICard = ({ title, value, change, icon: Icon, loading }) => {
    const isPositive = change >= 0;

    if (loading) {
        return (
            <div className="border border-border rounded-md p-6 bg-card">
                <Skeleton className="h-4 w-24 mb-4" />
                <Skeleton className="h-10 w-32 mb-2" />
                <Skeleton className="h-4 w-20" />
            </div>
        );
    }

    return (
        <div className="border border-border rounded-md p-6 bg-card card-hover" data-testid={`kpi-${title.toLowerCase().replace(/ /g, '-')}`}>
            <div className="flex items-center justify-between mb-4">
                <span className="section-label">{title}</span>
                <div className="w-10 h-10 rounded-md bg-primary/10 flex items-center justify-center">
                    <Icon size={20} weight="duotone" className="text-primary" />
                </div>
            </div>
            <p className="kpi-value mb-2" data-testid={`kpi-value-${title.toLowerCase().replace(/ /g, '-')}`}>
                {value}
            </p>
            <div className="flex items-center gap-1">
                {isPositive ? (
                    <TrendUp size={16} weight="bold" className="text-green-500" />
                ) : (
                    <TrendDown size={16} weight="bold" className="text-red-500" />
                )}
                <span className={`text-sm font-medium ${isPositive ? 'text-green-500' : 'text-red-500'}`}>
                    {isPositive ? '+' : ''}{change}%
                </span>
                <span className="text-sm text-muted-foreground ml-1">vs last period</span>
            </div>
        </div>
    );
};

const CustomTooltip = ({ active, payload, label }) => {
    if (active && payload && payload.length) {
        return (
            <div className="custom-tooltip">
                <p className="custom-tooltip-label">{label}</p>
                {payload.map((entry, index) => (
                    <p key={index} className="custom-tooltip-value">
                        {entry.name}: {typeof entry.value === 'number' && entry.name.includes('Revenue') 
                            ? `$${entry.value.toLocaleString()}`
                            : entry.value.toLocaleString()}
                    </p>
                ))}
            </div>
        );
    }
    return null;
};

export default function Dashboard() {
    const { theme } = useTheme();
    const colors = CHART_COLORS[theme];

    const [kpis, setKpis] = useState(null);
    const [revenueData, setRevenueData] = useState([]);
    const [productsData, setProductsData] = useState([]);
    const [countriesData, setCountriesData] = useState([]);
    const [segmentsData, setSegmentsData] = useState([]);
    const [loading, setLoading] = useState(true);

    // Filters
    const [dateRange, setDateRange] = useState('all');
    const [country, setCountry] = useState('all');
    const [category, setCategory] = useState('all');

    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            try {
                const [kpisRes, revenueRes, productsRes, countriesRes, segmentsRes] = await Promise.all([
                    axios.get(`${API}/dashboard/kpis`),
                    axios.get(`${API}/dashboard/revenue`),
                    axios.get(`${API}/dashboard/products`),
                    axios.get(`${API}/dashboard/countries`),
                    axios.get(`${API}/dashboard/segments`)
                ]);

                setKpis(kpisRes.data);
                setRevenueData(revenueRes.data);
                setProductsData(productsRes.data);
                setCountriesData(countriesRes.data);
                setSegmentsData(segmentsRes.data);
            } catch (error) {
                console.error('Error fetching dashboard data:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchData();
    }, []);

    const formatCurrency = (value) => {
        if (value >= 1000000) {
            return `$${(value / 1000000).toFixed(2)}M`;
        }
        if (value >= 1000) {
            return `$${(value / 1000).toFixed(1)}K`;
        }
        return `$${value.toFixed(2)}`;
    };

    return (
        <div className="page-container">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                {/* Header */}
                <div className="mb-8">
                    <p className="section-label mb-2">Analytics Overview</p>
                    <h1 className="text-3xl font-bold tracking-tight">Dashboard</h1>
                </div>

                {/* Filters */}
                <div className="flex flex-wrap gap-4 mb-8 p-4 border border-border rounded-md bg-card" data-testid="filters-container">
                    <div className="flex items-center gap-2">
                        <Funnel size={18} className="text-muted-foreground" />
                        <span className="text-sm font-medium">Filters:</span>
                    </div>
                    <Select value={dateRange} onValueChange={setDateRange}>
                        <SelectTrigger className="w-[140px]" data-testid="filter-date-range">
                            <SelectValue placeholder="Date Range" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">All Time</SelectItem>
                            <SelectItem value="30d">Last 30 Days</SelectItem>
                            <SelectItem value="90d">Last 90 Days</SelectItem>
                            <SelectItem value="1y">Last Year</SelectItem>
                        </SelectContent>
                    </Select>
                    <Select value={country} onValueChange={setCountry}>
                        <SelectTrigger className="w-[140px]" data-testid="filter-country">
                            <SelectValue placeholder="Country" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">All Countries</SelectItem>
                            <SelectItem value="us">United States</SelectItem>
                            <SelectItem value="uk">United Kingdom</SelectItem>
                            <SelectItem value="de">Germany</SelectItem>
                            <SelectItem value="ca">Canada</SelectItem>
                        </SelectContent>
                    </Select>
                    <Select value={category} onValueChange={setCategory}>
                        <SelectTrigger className="w-[160px]" data-testid="filter-category">
                            <SelectValue placeholder="Category" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">All Categories</SelectItem>
                            <SelectItem value="electronics">Electronics</SelectItem>
                            <SelectItem value="home">Home & Garden</SelectItem>
                            <SelectItem value="fashion">Fashion</SelectItem>
                        </SelectContent>
                    </Select>
                </div>

                {/* KPI Cards */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
                    <KPICard
                        title="Total Revenue"
                        value={kpis ? formatCurrency(kpis.total_revenue) : '-'}
                        change={kpis?.revenue_growth || 0}
                        icon={CurrencyDollar}
                        loading={loading}
                    />
                    <KPICard
                        title="Total Orders"
                        value={kpis ? kpis.total_orders.toLocaleString() : '-'}
                        change={kpis?.orders_growth || 0}
                        icon={ShoppingCart}
                        loading={loading}
                    />
                    <KPICard
                        title="Total Customers"
                        value={kpis ? kpis.total_customers.toLocaleString() : '-'}
                        change={kpis?.customers_growth || 0}
                        icon={Users}
                        loading={loading}
                    />
                    <KPICard
                        title="Avg Order Value"
                        value={kpis ? `$${kpis.avg_order_value.toFixed(2)}` : '-'}
                        change={3.8}
                        icon={Receipt}
                        loading={loading}
                    />
                </div>

                {/* Charts Grid */}
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                    {/* Revenue Over Time */}
                    <div className="border border-border rounded-md p-6 bg-card" data-testid="chart-revenue">
                        <h3 className="font-semibold mb-1">Revenue Over Time</h3>
                        <p className="text-sm text-muted-foreground mb-4">Monthly revenue trend for the year</p>
                        {loading ? (
                            <Skeleton className="h-[300px] w-full" />
                        ) : (
                            <ResponsiveContainer width="100%" height={300}>
                                <AreaChart data={revenueData}>
                                    <defs>
                                        <linearGradient id="revenueGradient" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor={colors.primary} stopOpacity={0.3}/>
                                            <stop offset="95%" stopColor={colors.primary} stopOpacity={0}/>
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" stroke={colors.grid} vertical={false} />
                                    <XAxis 
                                        dataKey="month" 
                                        stroke={colors.text} 
                                        fontSize={12}
                                        tickLine={false}
                                        axisLine={false}
                                    />
                                    <YAxis 
                                        stroke={colors.text} 
                                        fontSize={12}
                                        tickLine={false}
                                        axisLine={false}
                                        tickFormatter={(value) => `$${(value/1000).toFixed(0)}K`}
                                    />
                                    <Tooltip content={<CustomTooltip />} />
                                    <Area 
                                        type="monotone" 
                                        dataKey="revenue" 
                                        name="Revenue"
                                        stroke={colors.primary} 
                                        strokeWidth={2}
                                        fill="url(#revenueGradient)"
                                    />
                                </AreaChart>
                            </ResponsiveContainer>
                        )}
                    </div>

                    {/* Top Products */}
                    <div className="border border-border rounded-md p-6 bg-card" data-testid="chart-products">
                        <h3 className="font-semibold mb-1">Top Products</h3>
                        <p className="text-sm text-muted-foreground mb-4">Best selling products by units sold</p>
                        {loading ? (
                            <Skeleton className="h-[300px] w-full" />
                        ) : (
                            <ResponsiveContainer width="100%" height={300}>
                                <BarChart data={productsData.slice(0, 6)} layout="vertical">
                                    <CartesianGrid strokeDasharray="3 3" stroke={colors.grid} horizontal={false} />
                                    <XAxis 
                                        type="number" 
                                        stroke={colors.text} 
                                        fontSize={12}
                                        tickLine={false}
                                        axisLine={false}
                                    />
                                    <YAxis 
                                        type="category" 
                                        dataKey="name" 
                                        stroke={colors.text} 
                                        fontSize={11}
                                        tickLine={false}
                                        axisLine={false}
                                        width={120}
                                    />
                                    <Tooltip content={<CustomTooltip />} />
                                    <Bar 
                                        dataKey="sales" 
                                        name="Units Sold"
                                        fill={colors.primary} 
                                        radius={[0, 4, 4, 0]}
                                    />
                                </BarChart>
                            </ResponsiveContainer>
                        )}
                    </div>

                    {/* Sales by Country */}
                    <div className="border border-border rounded-md p-6 bg-card" data-testid="chart-countries">
                        <h3 className="font-semibold mb-1">Sales by Country</h3>
                        <p className="text-sm text-muted-foreground mb-4">Revenue distribution by region</p>
                        {loading ? (
                            <Skeleton className="h-[300px] w-full" />
                        ) : (
                            <ResponsiveContainer width="100%" height={300}>
                                <BarChart data={countriesData}>
                                    <CartesianGrid strokeDasharray="3 3" stroke={colors.grid} vertical={false} />
                                    <XAxis 
                                        dataKey="country" 
                                        stroke={colors.text} 
                                        fontSize={11}
                                        tickLine={false}
                                        axisLine={false}
                                        angle={-45}
                                        textAnchor="end"
                                        height={80}
                                    />
                                    <YAxis 
                                        stroke={colors.text} 
                                        fontSize={12}
                                        tickLine={false}
                                        axisLine={false}
                                        tickFormatter={(value) => `$${(value/1000).toFixed(0)}K`}
                                    />
                                    <Tooltip content={<CustomTooltip />} />
                                    <Bar 
                                        dataKey="revenue" 
                                        name="Revenue"
                                        fill={colors.secondary} 
                                        radius={[4, 4, 0, 0]}
                                    />
                                </BarChart>
                            </ResponsiveContainer>
                        )}
                    </div>

                    {/* Customer Segmentation */}
                    <div className="border border-border rounded-md p-6 bg-card" data-testid="chart-segments">
                        <h3 className="font-semibold mb-1">Customer Segmentation</h3>
                        <p className="text-sm text-muted-foreground mb-4">Distribution by customer value tier</p>
                        {loading ? (
                            <Skeleton className="h-[300px] w-full" />
                        ) : (
                            <div className="flex items-center">
                                <ResponsiveContainer width="60%" height={300}>
                                    <PieChart>
                                        <Pie
                                            data={segmentsData}
                                            cx="50%"
                                            cy="50%"
                                            innerRadius={60}
                                            outerRadius={100}
                                            paddingAngle={2}
                                            dataKey="percentage"
                                            nameKey="segment"
                                        >
                                            {segmentsData.map((entry, index) => (
                                                <Cell 
                                                    key={`cell-${index}`} 
                                                    fill={PIE_COLORS[index % PIE_COLORS.length]} 
                                                />
                                            ))}
                                        </Pie>
                                        <Tooltip content={<CustomTooltip />} />
                                    </PieChart>
                                </ResponsiveContainer>
                                <div className="w-[40%] space-y-3">
                                    {segmentsData.map((segment, index) => (
                                        <div key={segment.segment} className="flex items-center gap-2">
                                            <div 
                                                className="w-3 h-3 rounded-sm" 
                                                style={{ backgroundColor: PIE_COLORS[index] }}
                                            />
                                            <div className="flex-1 min-w-0">
                                                <p className="text-xs text-muted-foreground truncate">{segment.segment}</p>
                                                <p className="text-sm font-medium font-mono">{segment.percentage}%</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}
